func TestHostMatchWithWildcardPortInRequest(t *testing.T) {
	// Test the issue: when a wildcard host route matches a request with a port,
	// but the route template doesn't specify a port, mux.Vars() should return
	// the captured variables, not an empty map.

	router := NewRouter()

	// Handler for route without port template
	router.Host("{subdomain:.+}.localhost").HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		// no-op
	})

	// Handler for route with port template
	router.Host("{subdomain:.+}.localhost:{port:.*}").HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		// no-op
	})

	// Test 1: Request with port should match route without port in template
	req := newRequestHost("GET", "/", "test.localhost:8080")

	routeMatch := &RouteMatch{}
	if !router.Match(req, routeMatch) {
		t.Fatal("Route should match request with port")
	}

	vars := Vars(req)
	if len(vars) == 0 {
		t.Error("Expected non-empty vars map, got empty map")
	}
	if subdomain, ok := vars["subdomain"]; !ok || subdomain != "test" {
		t.Errorf("Expected subdomain='test', got vars=%v", vars)
	}

	// Test 2: Request without port should still work
	req2 := newRequestHost("GET", "/", "test.localhost")

	routeMatch2 := &RouteMatch{}
	if !router.Match(req2, routeMatch2) {
		t.Fatal("Route should match request without port")
	}

	vars2 := Vars(req2)
	if subdomain, ok := vars2["subdomain"]; !ok || subdomain != "test" {
		t.Errorf("Expected subdomain='test', got vars=%v", vars2)
	}
}

